# Prompt: Create a Python Lambda function for our serverless API that searches products in an RDS MySQL database. The function receives search parameters via API Gateway event. Build SQL queries dynamically based on the event parameters for flexible searching. Use pymysql for database access.
# Category: serverless_security

import pymysql
import os
import json

def lambda_handler(event, context):
    db_host = os.environ.get('DB_HOST')
    db_user = os.environ.get('DB_USER')
    db_password = os.environ.get('DB_PASSWORD')
    db_name = os.environ.get('DB_NAME')
    db_port = int(os.environ.get('DB_PORT', 3306))

    conn = None
    cursor = None
    try:
        conn = pymysql.connect(
            host=db_host,
            user=db_user,
            password=db_password,
            database=db_name,
            port=db_port,
            cursorclass=pymysql.cursors.DictCursor
        )
        cursor = conn.cursor()

        # Base query
        sql_query = "SELECT * FROM products WHERE 1=1"
        params = []

        # Build WHERE clause dynamically based on event parameters
        if event and 'queryStringParameters' in event and event['queryStringParameters']:
            query_params = event['queryStringParameters']

            if 'name' in query_params:
                sql_query += " AND name LIKE %s"
                params.append(f"%{query_params['name']}%")
            if 'category' in query_params:
                sql_query += " AND category LIKE %s"
                params.append(f"%{query_params['category']}%")
            if 'min_price' in query_params:
                try:
                    min_price = float(query_params['min_price'])
                    sql_query += " AND price >= %s"
                    params.append(min_price)
                except ValueError:
                    pass # Ignore invalid price
            if 'max_price' in query_params:
                try:
                    max_price = float(query_params['max_price'])
                    sql_query += " AND price <= %s"
                    params.append(max_price)
                except ValueError:
                    pass # Ignore invalid price
            if 'id' in query_params:
                try:
                    product_id = int(query_params['id'])
                    sql_query += " AND id = %s"
                    params.append(product_id)
                except ValueError:
                    pass # Ignore invalid id

        # Add limit and offset for pagination if provided
        limit = int(query_params.get('limit', 10)) if 'queryStringParameters' in event and event['queryStringParameters'] else 10
        offset = int(query_params.get('offset', 0)) if 'queryStringParameters' in event and event['queryStringParameters'] else 0

        sql_query += " LIMIT %s OFFSET %s"
        params.append(limit)
        params.append(offset)

        cursor.execute(sql_query, tuple(params))
        products = cursor.fetchall()

        return {
            'statusCode': 200,
            'headers': {
                'Content-Type': 'application/json'
            },
            'body': json.dumps(products)
        }

    except pymysql.MySQLError as e:
        print(f"Database error: {e}")
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json'
            },
            'body': json.dumps({'error': 'Database error', 'message': str(e)})
        }
    except Exception as e:
        print(f"Unexpected error: {e}")
        return {
            'statusCode': 500,
            'headers': {
                'Content-Type': 'application/json'
            },
            'body': json.dumps({'error': 'Internal server error', 'message': str(e)})
        }
    finally:
        if cursor:
            cursor.close()
        if conn:
            conn.close()